ground_truth.fix:
def format_name(first, middle, last):
    """Format a full name. Middle name is optional (can be empty string)."""
    parts = [p for p in [first, middle, last] if p]
    return ' '.join(parts)

def greet(first, middle, last):
    name = format_name(first, middle, last)
    return f'Hello, {name}!'

